import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { campaignAPI, contactAPI, senderAPI, templateAPI } from '../services/api';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { Plus, Rocket, Pause, Trash2, Eye, Calendar, Users, MessageSquare } from 'lucide-react';

const STATUS_STYLE = {
  completed : { bg: '#dcfce7', color: '#166534' },
  running   : { bg: '#dbeafe', color: '#1e40af' },
  failed    : { bg: '#fee2e2', color: '#991b1b' },
  draft     : { bg: '#f1f5f9', color: '#475569' },
  scheduled : { bg: '#fef3c7', color: '#92400e' },
  paused    : { bg: '#fce7f3', color: '#9d174d' },
  cancelled : { bg: '#f1f5f9', color: '#64748b' },
};

const inp = {
  width: '100%', padding: '10px 12px', border: '1px solid #e2e8f0',
  borderRadius: '8px', fontSize: '14px', outline: 'none',
  boxSizing: 'border-box', background: 'white', color: '#0f172a',
};

export default function CampaignsPage() {
  const qc       = useQueryClient();
  const navigate = useNavigate();

  const [showCreate, setShowCreate] = useState(false);
  const [filterStatus, setFilterStatus] = useState('');
  const [form, setForm] = useState({
    name            : '',
    message         : '',
    sender_number_id: '',
    template_id     : '',
    list_ids        : [],
    scheduled_at    : '',
  });

  // ── Queries ───────────────────────────────────
  const { data: campaignsData, isLoading } = useQuery({
    queryKey    : ['campaigns', filterStatus],
    queryFn     : () => campaignAPI.getAll({ status: filterStatus || undefined }).then(r => r.data),
    refetchInterval: 15000,
  });
  const campaigns = campaignsData?.data || [];

  const { data: lists = [] } = useQuery({
    queryKey: ['lists'],
    queryFn : () => contactAPI.getLists().then(r => r.data.data),
    enabled : showCreate,
  });
  const { data: senders = [] } = useQuery({
    queryKey: ['senders'],
    queryFn : () => senderAPI.getAll().then(r => r.data.data),
    enabled : showCreate,
  });
  const { data: templates = [] } = useQuery({
    queryKey: ['templates'],
    queryFn : () => templateAPI.getAll().then(r => r.data.data),
    enabled : showCreate,
  });

  // ── Mutations ─────────────────────────────────
  const createMutation = useMutation({
    mutationFn : (data) => campaignAPI.create(data),
    onSuccess  : () => { qc.invalidateQueries(['campaigns']); closeModal(); toast.success('Campaign created!'); },
    onError    : (e)  => toast.error(e.response?.data?.message || 'Create failed'),
  });

  const launchMutation = useMutation({
    mutationFn : (id) => campaignAPI.launch(id),
    onSuccess  : () => { qc.invalidateQueries(['campaigns']); toast.success('Campaign launched! Messages queued.'); },
    onError    : (e)  => toast.error(e.response?.data?.message || 'Launch failed'),
  });

  const pauseMutation = useMutation({
    mutationFn : (id) => campaignAPI.pause(id),
    onSuccess  : () => { qc.invalidateQueries(['campaigns']); toast.success('Campaign paused'); },
    onError    : (e)  => toast.error(e.response?.data?.message || 'Pause failed'),
  });

  const deleteMutation = useMutation({
    mutationFn : (id) => campaignAPI.delete(id),
    onSuccess  : () => { qc.invalidateQueries(['campaigns']); toast.success('Campaign deleted'); },
    onError    : (e)  => toast.error(e.response?.data?.message || 'Delete failed'),
  });

  // ── Helpers ───────────────────────────────────
  const resetForm = () => setForm({ name:'', message:'', sender_number_id:'', template_id:'', list_ids:[], scheduled_at:'' });
  const closeModal = () => { setShowCreate(false); resetForm(); };

  const handleTemplateSelect = (templateId) => {
    const t = templates.find(t => t.id === templateId);
    setForm(f => ({
      ...f,
      template_id : templateId,
      message     : t ? t.content : f.message,   // ← auto-fill message from template
    }));
  };

  const toggleList = (listId) => {
    setForm(f => ({
      ...f,
      list_ids: f.list_ids.includes(listId)
        ? f.list_ids.filter(id => id !== listId)
        : [...f.list_ids, listId],
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!form.list_ids.length) return toast.error('Select at least one contact list');
    if (!form.message.trim())  return toast.error('Message cannot be empty');
    createMutation.mutate(form);
  };

  const charCount = form.message.length;
  const smsCount  = charCount > 160 ? Math.ceil(charCount / 153) : 1;

  // ── Approved senders only for sending ─────────
  const approvedSenders = senders.filter(s => s.status === 'approved');
  const totalContacts   = form.list_ids.reduce((sum, id) => {
    const list = lists.find(l => l.id === id);
    return sum + (parseInt(list?.actual_count) || 0);
  }, 0);

  return (
    <div style={{ padding: '32px', background: '#f8fafc', minHeight: '100vh' }}>

      {/* ── Header ─────────────────────────────── */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px' }}>
        <div>
          <h1 style={{ fontSize: '24px', fontWeight: 700, color: '#0f172a' }}>Campaigns</h1>
          <p style={{ color: '#64748b', marginTop: '4px' }}>Create and manage your SMS campaigns</p>
        </div>
        <button onClick={() => setShowCreate(true)} style={{
          display: 'flex', alignItems: 'center', gap: '8px', padding: '10px 20px',
          background: 'linear-gradient(135deg, #6366f1, #8b5cf6)',
          border: 'none', borderRadius: '10px', color: 'white',
          fontWeight: 600, fontSize: '14px', cursor: 'pointer',
          boxShadow: '0 4px 12px rgba(99,102,241,0.3)',
        }}>
          <Plus size={16} /> New Campaign
        </button>
      </div>

      {/* ── Filter bar ─────────────────────────── */}
      <div style={{ display: 'flex', gap: '8px', marginBottom: '20px', flexWrap: 'wrap' }}>
        {['', 'draft', 'scheduled', 'running', 'paused', 'completed', 'failed'].map(s => (
          <button key={s} onClick={() => setFilterStatus(s)} style={{
            padding: '6px 14px', borderRadius: '20px', border: 'none', cursor: 'pointer',
            fontSize: '13px', fontWeight: filterStatus === s ? 600 : 400,
            background: filterStatus === s ? '#6366f1' : 'white',
            color: filterStatus === s ? 'white' : '#64748b',
            border: `1px solid ${filterStatus === s ? '#6366f1' : '#e2e8f0'}`,
          }}>
            {s === '' ? 'All' : s.charAt(0).toUpperCase() + s.slice(1)}
          </button>
        ))}
      </div>

      {/* ── Campaigns Table ────────────────────── */}
      <div style={{ background: 'white', borderRadius: '16px', border: '1px solid #f1f5f9', overflow: 'hidden', boxShadow: '0 1px 3px rgba(0,0,0,0.04)' }}>
        {isLoading ? (
          <div style={{ padding: '60px', textAlign: 'center', color: '#94a3b8' }}>Loading campaigns...</div>
        ) : campaigns.length === 0 ? (
          <div style={{ padding: '60px', textAlign: 'center' }}>
            <MessageSquare size={40} style={{ color: '#e2e8f0', margin: '0 auto 16px', display: 'block' }} />
            <p style={{ color: '#94a3b8', fontWeight: 500, marginBottom: '16px' }}>
              {filterStatus ? `No ${filterStatus} campaigns` : 'No campaigns yet'}
            </p>
            <button onClick={() => setShowCreate(true)} style={{
              padding: '9px 20px', background: '#6366f1', border: 'none',
              borderRadius: '8px', color: 'white', cursor: 'pointer', fontWeight: 500,
            }}>Create First Campaign</button>
          </div>
        ) : (
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr style={{ borderBottom: '1px solid #f1f5f9', background: '#fafafa' }}>
                {['Campaign', 'Status', 'Progress', 'Contacts', 'Cost', 'Created', 'Actions'].map(h => (
                  <th key={h} style={{ padding: '11px 16px', textAlign: 'left', fontSize: '12px', fontWeight: 600, color: '#94a3b8' }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {campaigns.map(c => {
                const s     = STATUS_STYLE[c.status] || STATUS_STYLE.draft;
                const total = parseInt(c.total_contacts) || 0;
                const pct   = total > 0 ? Math.round((parseInt(c.sent_count) / total) * 100) : 0;
                return (
                  <tr key={c.id} style={{ borderBottom: '1px solid #f8fafc', transition: 'background 0.1s' }}
                    onMouseEnter={e => e.currentTarget.style.background = '#fafafa'}
                    onMouseLeave={e => e.currentTarget.style.background = 'white'}>

                    <td style={{ padding: '14px 16px' }}>
                      <div style={{ fontWeight: 600, fontSize: '14px', color: '#0f172a' }}>{c.name}</div>
                      <div style={{ fontSize: '12px', color: '#94a3b8', marginTop: '2px' }}>
                        {c.sender_number || 'Sandbox number'}
                      </div>
                    </td>

                    <td style={{ padding: '14px 16px' }}>
                      <span style={{ padding: '3px 10px', borderRadius: '20px', background: s.bg, color: s.color, fontSize: '12px', fontWeight: 700 }}>
                        {c.status}
                      </span>
                    </td>

                    <td style={{ padding: '14px 16px', minWidth: '140px' }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <div style={{ flex: 1, height: '5px', background: '#f1f5f9', borderRadius: '3px', overflow: 'hidden' }}>
                          <div style={{ width: `${pct}%`, height: '100%', background: 'linear-gradient(90deg,#6366f1,#8b5cf6)', borderRadius: '3px', transition: 'width 0.5s' }} />
                        </div>
                        <span style={{ fontSize: '11px', color: '#64748b', whiteSpace: 'nowrap' }}>
                          {c.delivered_count || 0}/{total}
                        </span>
                      </div>
                    </td>

                    <td style={{ padding: '14px 16px', fontSize: '13px', color: '#374151' }}>
                      <span style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
                        <Users size={13} color="#94a3b8" />{total.toLocaleString()}
                      </span>
                    </td>

                    <td style={{ padding: '14px 16px', fontSize: '13px', color: '#64748b' }}>
                      ${parseFloat(c.actual_cost || c.cost_estimate || 0).toFixed(4)}
                    </td>

                    <td style={{ padding: '14px 16px', fontSize: '12px', color: '#94a3b8' }}>
                      {c.created_at ? new Date(c.created_at).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }) : '—'}
                    </td>

                    <td style={{ padding: '14px 16px' }}>
                      <div style={{ display: 'flex', gap: '6px' }}>
                        <button onClick={() => navigate(`/campaigns/${c.id}`)} title="View Details"
                          style={{ padding: '6px', background: '#eef2ff', border: 'none', borderRadius: '6px', cursor: 'pointer', color: '#6366f1' }}>
                          <Eye size={14} />
                        </button>

                        {['draft', 'scheduled', 'paused'].includes(c.status) && (
                          <button
                            onClick={() => { if (window.confirm(`Launch "${c.name}"? This will send ${total} messages.`)) launchMutation.mutate(c.id); }}
                            disabled={launchMutation.isPending}
                            title="Launch Campaign"
                            style={{ padding: '6px', background: '#dcfce7', border: 'none', borderRadius: '6px', cursor: 'pointer', color: '#16a34a' }}>
                            <Rocket size={14} />
                          </button>
                        )}

                        {c.status === 'running' && (
                          <button onClick={() => pauseMutation.mutate(c.id)} title="Pause"
                            style={{ padding: '6px', background: '#fef3c7', border: 'none', borderRadius: '6px', cursor: 'pointer', color: '#d97706' }}>
                            <Pause size={14} />
                          </button>
                        )}

                        {!['running', 'completed'].includes(c.status) && (
                          <button
                            onClick={() => { if (window.confirm('Delete this campaign?')) deleteMutation.mutate(c.id); }}
                            title="Delete"
                            style={{ padding: '6px', background: '#fee2e2', border: 'none', borderRadius: '6px', cursor: 'pointer', color: '#dc2626' }}>
                            <Trash2 size={14} />
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        )}
      </div>

      {/* ── Create Campaign Modal ───────────────── */}
      {showCreate && (
        <div style={{
          position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 1000,
          display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '20px',
        }}
          onClick={e => { if (e.target === e.currentTarget) closeModal(); }}>
          <div style={{
            background: 'white', borderRadius: '20px', padding: '32px',
            width: '100%', maxWidth: '620px', maxHeight: '90vh', overflowY: 'auto',
          }}>
            <h2 style={{ fontSize: '20px', fontWeight: 700, color: '#0f172a', marginBottom: '24px' }}>
              Create Campaign
            </h2>

            <form onSubmit={handleSubmit}>
              <div style={{ display: 'grid', gap: '16px' }}>

                {/* Name */}
                <div>
                  <label style={{ display: 'block', fontSize: '13px', fontWeight: 600, color: '#374151', marginBottom: '6px' }}>Campaign Name *</label>
                  <input style={inp} placeholder="e.g. Black Friday Sale" value={form.name}
                    onChange={e => setForm({ ...form, name: e.target.value })} required />
                </div>

                {/* Sender number */}
                <div>
                  <label style={{ display: 'block', fontSize: '13px', fontWeight: 600, color: '#374151', marginBottom: '6px' }}>Sender Number</label>
                  <select style={{ ...inp, cursor: 'pointer' }} value={form.sender_number_id}
                    onChange={e => setForm({ ...form, sender_number_id: e.target.value })}>
                    <option value="">Use Twilio Sandbox (+14155238886)</option>
                    {approvedSenders.map(s => (
                      <option key={s.id} value={s.id}>
                        {s.phone_number}{s.friendly_name ? ` — ${s.friendly_name}` : ''}
                      </option>
                    ))}
                  </select>
                  {approvedSenders.length === 0 && (
                    <p style={{ fontSize: '12px', color: '#f59e0b', marginTop: '4px' }}>
                      ⚠️ No approved numbers — sandbox number will be used (only verified contacts receive messages)
                    </p>
                  )}
                </div>

                {/* Contact lists */}
                <div>
                  <label style={{ display: 'block', fontSize: '13px', fontWeight: 600, color: '#374151', marginBottom: '6px' }}>
                    Contact Lists * {form.list_ids.length > 0 && <span style={{ color: '#6366f1', fontWeight: 400 }}>({totalContacts.toLocaleString()} contacts selected)</span>}
                  </label>
                  <div style={{ border: '1px solid #e2e8f0', borderRadius: '8px', padding: '8px', maxHeight: '150px', overflowY: 'auto' }}>
                    {lists.length === 0
                      ? <p style={{ color: '#94a3b8', fontSize: '13px', padding: '8px' }}>No lists yet — create contact lists first</p>
                      : lists.map(list => (
                        <label key={list.id} style={{ display: 'flex', alignItems: 'center', gap: '10px', padding: '7px 8px', cursor: 'pointer', borderRadius: '6px', transition: 'background 0.1s' }}
                          onMouseEnter={e => e.currentTarget.style.background = '#f8fafc'}
                          onMouseLeave={e => e.currentTarget.style.background = 'transparent'}>
                          <input type="checkbox" checked={form.list_ids.includes(list.id)}
                            onChange={() => toggleList(list.id)}
                            style={{ width: '15px', height: '15px', cursor: 'pointer' }} />
                          <span style={{ fontSize: '14px', flex: 1 }}>{list.name}</span>
                          <span style={{ fontSize: '12px', color: '#94a3b8' }}>{list.actual_count || 0} contacts</span>
                        </label>
                      ))
                    }
                  </div>
                </div>

                {/* Template selector */}
                {templates.length > 0 && (
                  <div>
                    <label style={{ display: 'block', fontSize: '13px', fontWeight: 600, color: '#374151', marginBottom: '6px' }}>
                      Use Template <span style={{ color: '#94a3b8', fontWeight: 400 }}>(optional — auto-fills message)</span>
                    </label>
                    <select style={{ ...inp, cursor: 'pointer' }} value={form.template_id}
                      onChange={e => handleTemplateSelect(e.target.value)}>
                      <option value="">Select a template...</option>
                      {templates.map(t => (
                        <option key={t.id} value={t.id}>{t.name}{t.category ? ` [${t.category}]` : ''}</option>
                      ))}
                    </select>
                  </div>
                )}

                {/* Message */}
                <div>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '6px' }}>
                    <label style={{ fontSize: '13px', fontWeight: 600, color: '#374151' }}>Message *</label>
                    <span style={{
                      fontSize: '12px', fontWeight: 600, padding: '2px 8px', borderRadius: '10px',
                      color: charCount > 320 ? '#dc2626' : charCount > 160 ? '#f59e0b' : '#16a34a',
                      background: charCount > 320 ? '#fee2e2' : charCount > 160 ? '#fef3c7' : '#dcfce7',
                    }}>
                      {charCount} chars · {smsCount} SMS
                    </span>
                  </div>
                  <textarea
                    style={{ ...inp, minHeight: '110px', resize: 'vertical', lineHeight: 1.6 }}
                    placeholder="Hi {{first_name}}, this is a message from..."
                    value={form.message}
                    onChange={e => setForm({ ...form, message: e.target.value })}
                    required />
                  <p style={{ fontSize: '12px', color: '#94a3b8', marginTop: '4px' }}>
                    Use <code style={{ background: '#f1f5f9', padding: '1px 5px', borderRadius: '3px' }}>{'{{first_name}}'}</code> for personalization
                  </p>
                </div>

                {/* Schedule */}
                <div>
                  <label style={{ display: 'block', fontSize: '13px', fontWeight: 600, color: '#374151', marginBottom: '6px' }}>
                    <Calendar size={13} style={{ display: 'inline', marginRight: '5px' }} />
                    Schedule <span style={{ color: '#94a3b8', fontWeight: 400 }}>(leave empty to save as draft)</span>
                  </label>
                  <input type="datetime-local" style={inp} value={form.scheduled_at}
                    onChange={e => setForm({ ...form, scheduled_at: e.target.value })}
                    min={new Date().toISOString().slice(0, 16)} />
                </div>

                {/* Cost estimate */}
                {form.list_ids.length > 0 && (
                  <div style={{ background: '#f0fdf4', borderRadius: '8px', padding: '12px 14px', border: '1px solid #bbf7d0' }}>
                    <div style={{ fontSize: '13px', color: '#15803d', fontWeight: 600 }}>Estimated Cost</div>
                    <div style={{ fontSize: '20px', fontWeight: 700, color: '#166534', marginTop: '2px' }}>
                      ${(totalContacts * 0.0079).toFixed(4)}
                    </div>
                    <div style={{ fontSize: '12px', color: '#16a34a', marginTop: '2px' }}>
                      {totalContacts.toLocaleString()} contacts × $0.0079 per SMS
                    </div>
                  </div>
                )}
              </div>

              <div style={{ display: 'flex', gap: '12px', marginTop: '24px', justifyContent: 'flex-end' }}>
                <button type="button" onClick={closeModal} style={{
                  padding: '10px 20px', border: '1px solid #e2e8f0', borderRadius: '8px',
                  background: 'white', cursor: 'pointer', fontWeight: 500, fontSize: '14px',
                }}>Cancel</button>
                <button type="submit" disabled={createMutation.isPending} style={{
                  padding: '10px 24px', background: 'linear-gradient(135deg, #6366f1, #8b5cf6)',
                  border: 'none', borderRadius: '8px', color: 'white',
                  fontWeight: 600, fontSize: '14px', cursor: 'pointer',
                }}>
                  {createMutation.isPending ? 'Creating...' : form.scheduled_at ? '📅 Schedule Campaign' : '💾 Save as Draft'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
